package com.example.auth

import android.content.Context
import android.content.SharedPreferences

data class AuthSession(
    val authToken: String,
    val userId: String
)

class AuthenticationManager(context: Context) {

    private val prefs: SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    fun saveLoginState(authToken: String, userId: String) {
        prefs.edit()
            .putString(KEY_AUTH_TOKEN, authToken)
            .putString(KEY_USER_ID, userId)
            .putBoolean(KEY_IS_LOGGED_IN, true)
            .apply()
    }

    fun getAuthSession(): AuthSession? {
        val token = prefs.getString(KEY_AUTH_TOKEN, null)
        val userId = prefs.getString(KEY_USER_ID, null)

        return if (!token.isNullOrBlank() && !userId.isNullOrBlank()) {
            AuthSession(authToken = token, userId = userId)
        } else {
            null
        }
    }

    fun isLoggedIn(): Boolean {
        return prefs.getBoolean(KEY_IS_LOGGED_IN, false)
            && !prefs.getString(KEY_AUTH_TOKEN, null).isNullOrBlank()
            && !prefs.getString(KEY_USER_ID, null).isNullOrBlank()
    }

    fun clearLoginState() {
        prefs.edit()
            .remove(KEY_AUTH_TOKEN)
            .remove(KEY_USER_ID)
            .putBoolean(KEY_IS_LOGGED_IN, false)
            .apply()
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
    }
}